import React, { useEffect, useRef } from 'react';
import { Animated, Easing, StyleSheet, View } from 'react-native';

const AnimatedCircle = () => {
  const sizeAnim = useRef(new Animated.Value(50)).current;
  const colorAnim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    // Animation parallèle pour la taille et la couleur
    Animated.parallel([
      Animated.timing(sizeAnim, {
        toValue: 150,
        duration: 1500,
        easing: Easing.bounce,
        useNativeDriver: false, // size affecte layout
      }),
      Animated.timing(colorAnim, {
        toValue: 1,
        duration: 1500,
        easing: Easing.bounce,
        useNativeDriver: false,
      }),
    ]).start(({ finished }) => {
      if (finished) {
        console.log('Animation terminée !');
      }
    });
  }, []);

  const backgroundColor = colorAnim.interpolate({
    inputRange: [0, 1],
    outputRange: ['#3B82F6', '#10B981'],
  });

  return (
    <View style={styles.container}>
      <Animated.View
        style={[
          styles.circle,
          {
            width: sizeAnim,
            height: sizeAnim,
            borderRadius: sizeAnim.interpolate({
              inputRange: [50, 150],
              outputRange: [25, 75],
            }),
            backgroundColor,
          },
        ]}
      />
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
  circle: {
    // Les styles dynamiques sont gérés ci-dessus
  },
});

export default AnimatedCircle;
