import React, { useState, useRef, useEffect } from 'react';
import { Animated, TouchableOpacity, Text, StyleSheet, View } from 'react-native';

const AnimatedCard = () => {
  const [visible, setVisible] = useState(false);
  const slideAnim = useRef(new Animated.Value(200)).current;
  const opacityAnim = useRef(new Animated.Value(0)).current;
  const blinkAnim = useRef(new Animated.Value(1)).current;
  const blinkLoop = useRef(null);

  const showCard = () => {
    setVisible(true);
    // Réinitialiser les valeurs
    slideAnim.setValue(200);
    opacityAnim.setValue(0);

    // Animation d'apparition : séquence avec parallélisme
    Animated.sequence([
      Animated.parallel([
        Animated.timing(slideAnim, {
          toValue: 0,
          duration: 500,
          useNativeDriver: true,
        }),
        Animated.timing(opacityAnim, {
          toValue: 1,
          duration: 500,
          useNativeDriver: true,
        }),
      ]),
      // Après apparition, démarrer le clignotement
      Animated.delay(100),
    ]).start(() => {
      // Boucle de clignotement
      blinkLoop.current = Animated.loop(
        Animated.sequence([
          Animated.timing(blinkAnim, {
            toValue: 0.3,
            duration: 500,
            useNativeDriver: true,
          }),
          Animated.timing(blinkAnim, {
            toValue: 1,
            duration: 500,
            useNativeDriver: true,
          }),
        ])
      );
      blinkLoop.current.start();
    });
  };

  const hideCard = () => {
    // Arrêter le clignotement
    if (blinkLoop.current) {
      blinkLoop.current.stop();
    }

    // Animation de disparition
    Animated.parallel([
      Animated.timing(slideAnim, {
        toValue: 200,
        duration: 400,
        useNativeDriver: true,
      }),
      Animated.timing(opacityAnim, {
        toValue: 0,
        duration: 400,
        useNativeDriver: true,
      }),
    ]).start(() => {
      setVisible(false);
      blinkAnim.setValue(1); // Réinitialiser
    });
  };

  if (!visible) {
    return (
      <TouchableOpacity style={styles.showButton} onPress={showCard}>
        <Text style={styles.buttonText}>Afficher la carte</Text>
      </TouchableOpacity>
    );
  }

  return (
    <View style={styles.container}>
      <Animated.View
        style={[
          styles.card,
          {
            transform: [{ translateY: slideAnim }],
            opacity: opacityAnim,
          },
        ]}
      >
        <Animated.Text style={[styles.cardText, { opacity: blinkAnim }]}>
          ✨ Information importante ! ✨
        </Animated.Text>
        <TouchableOpacity style={styles.closeButton} onPress={hideCard}>
          <Text style={styles.closeText}>Fermer</Text>
        </TouchableOpacity>
      </Animated.View>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    backgroundColor: '#f0f0f0',
  },
  showButton: {
    backgroundColor: '#3B82F6',
    padding: 12,
    borderRadius: 8,
  },
  buttonText: { color: 'white', fontWeight: 'bold' },
  card: {
    position: 'absolute',
    bottom: 50,
    left: 20,
    right: 20,
    backgroundColor: 'white',
    borderRadius: 16,
    padding: 20,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.25,
    elevation: 5,
    alignItems: 'center',
  },
  cardText: { fontSize: 18, textAlign: 'center', marginBottom: 16 },
  closeButton: { backgroundColor: '#EF4444', padding: 8, borderRadius: 6 },
  closeText: { color: 'white' },
});

export default AnimatedCard;
