import React, { useRef } from 'react';
import { Animated, Text, View, StyleSheet, Dimensions } from 'react-native';

const { height: screenHeight } = Dimensions.get('window');
const HEADER_HEIGHT = 250;
const MIN_HEADER_HEIGHT = 100;

const ParallaxHeader = () => {
  const scrollY = useRef(new Animated.Value(0)).current;

  // Calcul de la hauteur de l'en-tête en fonction du défilement
  const headerHeight = scrollY.interpolate({
    inputRange: [0, HEADER_HEIGHT - MIN_HEADER_HEIGHT],
    outputRange: [HEADER_HEIGHT, MIN_HEADER_HEIGHT],
    extrapolate: 'clamp',
  });

  // Facteur d'échelle pour l'image (effet parallaxe)
  const imageScale = scrollY.interpolate({
    inputRange: [0, 200],
    outputRange: [1, 0.4],
    extrapolateRight: 'clamp',
  });

  // Translation verticale de l'image pour un effet de zoom
  const imageTranslateY = scrollY.interpolate({
    inputRange: [0, 200],
    outputRange: [0, 50],
    extrapolateRight: 'clamp',
  });

  // Opacité du titre
  const titleOpacity = scrollY.interpolate({
    inputRange: [0, 150, HEADER_HEIGHT - MIN_HEADER_HEIGHT],
    outputRange: [1, 0.5, 0],
    extrapolate: 'clamp',
  });

  // Hauteur du contenu paddingTop pour compenser l'en-tête
  const contentPaddingTop = scrollY.interpolate({
    inputRange: [0, HEADER_HEIGHT - MIN_HEADER_HEIGHT],
    outputRange: [HEADER_HEIGHT, MIN_HEADER_HEIGHT],
    extrapolate: 'clamp',
  });

  return (
    <View style={styles.container}>
      <Animated.ScrollView
        showsVerticalScrollIndicator={false}
        scrollEventThrottle={16}
        onScroll={Animated.event(
          [{ nativeEvent: { contentOffset: { y: scrollY } } }],
          { useNativeDriver: false } // car on modifie height
        )}
      >
        <Animated.View style={{ paddingTop: contentPaddingTop }}>
          <View style={styles.content}>
            <Text style={styles.sectionTitle}>À propos</Text>
            <Text style={styles.text}>
              Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.
            </Text>
            <Text style={styles.sectionTitle}>Expériences</Text>
            <Text style={styles.text}>
              • Développeur React Native - 2023 à aujourd'hui{'\n'}
              • Stage en développement mobile - 2022{'\n'}
              • Projet personnel : application e-commerce
            </Text>
            <Text style={styles.sectionTitle}>Formation</Text>
            <Text style={styles.text}>
              Master en Informatique, spécialité Développement Mobile
            </Text>
          </View>
        </Animated.View>
      </Animated.ScrollView>

      {/* En-tête fixe avec effet parallaxe */}
      <Animated.View
        style={[
          styles.header,
          {
            height: headerHeight,
          },
        ]}
      >
        <Animated.Image
          source={{ uri: 'https://picsum.photos/id/100/800/400' }}
          style={[
            styles.backgroundImage,
            {
              transform: [
                { scale: imageScale },
                { translateY: imageTranslateY },
              ],
            },
          ]}
          resizeMode="cover"
        />
        <Animated.View style={[styles.overlay, { opacity: titleOpacity }]}>
          <Text style={styles.title}>Mon Profil</Text>
          <Text style={styles.subtitle}>Développeur Mobile</Text>
        </Animated.View>
      </Animated.View>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#fff',
  },
  header: {
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    overflow: 'hidden',
  },
  backgroundImage: {
    width: '100%',
    height: '100%',
  },
  overlay: {
    position: 'absolute',
    bottom: 20,
    left: 0,
    right: 0,
    alignItems: 'center',
    backgroundColor: 'rgba(0,0,0,0.4)',
    paddingVertical: 10,
  },
  title: {
    fontSize: 28,
    fontWeight: 'bold',
    color: 'white',
  },
  subtitle: {
    fontSize: 16,
    color: 'white',
  },
  content: {
    padding: 20,
  },
  sectionTitle: {
    fontSize: 22,
    fontWeight: 'bold',
    marginTop: 20,
    marginBottom: 10,
    color: '#1F2937',
  },
  text: {
    fontSize: 16,
    lineHeight: 24,
    color: '#4B5563',
  },
});

export default ParallaxHeader;
