import React, { useState, useRef } from 'react';
import { TouchableOpacity, Animated, StyleSheet } from 'react-native';

const LikeButton = () => {
  const [liked, setLiked] = useState(false);
  const scaleAnim = useRef(new Animated.Value(1)).current;

  const animateLike = () => {
    // Animation de rebond
    Animated.sequence([
      Animated.spring(scaleAnim, {
        toValue: 1.4,
        friction: 7,
        tension: 100,
        useNativeDriver: true,
      }),
      Animated.spring(scaleAnim, {
        toValue: 1,
        friction: 7,
        tension: 100,
        useNativeDriver: true,
      }),
    ]).start();

    // Inverser l'état liké
    setLiked(!liked);
  };

  return (
    <TouchableOpacity onPress={animateLike} activeOpacity={0.7}>
      <Animated.View style={{ transform: [{ scale: scaleAnim }] }}>
        <Animated.Text style={[styles.heart, { color: liked ? '#EF4444' : '#9CA3AF' }]}>
          {liked ? '❤️' : '♡'}
        </Animated.Text>
      </Animated.View>
    </TouchableOpacity>
  );
};

const styles = StyleSheet.create({
  heart: {
    fontSize: 48,
  },
});

export default LikeButton;
